use actix_files::Files;
use actix_web::{web, App, HttpResponse, HttpServer, Responder};
use serde::{Deserialize, Serialize};
use std::sync::{Arc, Mutex};

#[derive(Debug, Clone)]
struct TextStore {
    texts: Vec<String>,
    current_index: usize,
}

impl TextStore {
    fn new() -> Self {
        // Загружаем фрагменты "Войны и мира"
        let fragments = vec![
            "Война и мир. Том первый. Часть первая. Глава первая — Ну что, князь, Генуя и Лукка больше не что иное, как родовые поместья семьи Бонапарт. Но я вас предупреждаю, что если вы не скажете мне, что у нас война, если вы ещё попытаетесь защитить бесчинства и ужасы этого Антихриста — слово чести, я вас больше не узнаю, вы больше не мой друг, вы больше не мой верный раб, как вы говорите. Ну, здравствуйте, здравствуйте. Садитесь и рассказывайте. Так говорила в июле 1805 года всем известная Анна Павловна Шерер, фрейлина и приближённая императрицы Марии Фёдоровны.".to_string(),
            "Этими словами она встретила князя Василия Курагина, сановника первой степени, важного человека, который первый явился на её вечер. Анна Павловна несколько дней кашляла; у неё был грипп, как она говорила. Грипп был тогда ещё новым словом в Петербурге, употребляемым только избранными. Все её приглашения без исключения были написаны по-французски и разосланы утром с лакеем в красной ливрее следующего содержания: «Если у вас, граф (или князь), нет ничего лучшего, и если перспектива провести вечер у бедной больной не слишком вас пугает, то я буду очень рада видеть вас сегодня между 7 и 10 часами. Аннет Шерер».".to_string(),
            "— Боже мой, какая злая болезнь! — ответил князь, ничуть не смущённый таким приёмом. Он вошёл в бальном мундире, в чулках и башмаках, со звёздами на груди и с ясным выражением на плоском лице. Он говорил на том изысканном французском языке, на котором не только говорили, но и думали наши деды, и с тем спокойным, покровительственным тоном, который свойствен человеку, состарившемуся в свете и при дворе. Он подошёл к Анне Павловне, поцеловал её руку, подставив ей свою лысую, надушенную и блестящую голову, и спокойно уселся на диване.".to_string(),
            "— Прежде всего, душа моя, скажите, как вы себя чувствуете? Успокойте вашего друга, — сказал он, не меняя тона, под учтивостью и притворным участием которого можно было разобрать равнодушие и даже иронию. — Можно ли быть здоровым, когда страдаешь нравственно? Разве можно в наше время быть спокойным, если у человека есть чувство? — сказала Анна Павловна. — Вы, надеюсь, останетесь весь вечер у меня? — А разве нет вечера у английского посланника? Сегодня среда. Мне нужно показаться там, — сказал князь. — Моя дочь заедет за мной, чтобы взять меня с собой.".to_string(),
            "— Я думала, что этот вечер отменён. Признаюсь, все эти празднества и фейерверки становятся несносными. — Если бы знали, что вы этого хотите, праздник был бы отменён, — сказал князь, который, как заведённые часы, по привычке говорил то, чему не хотел, чтобы верили. — Не дразните меня. Ну, что же решено насчёт депеши Новосильцева? Вы всё знаете. — Что можно сказать? — ответил князь холодным, скучающим тоном. — Что решено? Решили, что Бонапарт сжёг свои корабли, и я думаю, что мы готовы сжечь наши.".to_string(),
            "Князь Василий говорил всегда лениво, как актёр, играющий заученную роль. Анна Павловна Шерер, напротив, несмотря на свои сорок лет, была полна жизни и порыва. Быть энтузиасткой стало её общественным призванием, и иногда, даже когда она не чувствовала себя таковой, она становилась энтузиасткой, чтобы не обмануть ожиданий тех, кто её знал. Сдержанная улыбка, которая, хотя и не шла к её увядшему лицу, всегда играла на её губах, выражала, как у избалованного ребёнка, постоянное сознание своего прелестного недостатка, который она не хотела, не могла и не считала нужным исправлять.".to_string(),
            "В середине разговора о политических делах Анна Павловна вдруг воскликнула: — О, не говорите мне об Австрии! Может быть, я не понимаю вещей, но Австрия никогда не хотела и не хочет войны. Она нас предаёт! Одна Россия должна спасти Европу. Наш государь сознаёт своё высокое призвание и будет верен ему. В одно это я верю! Нашему доброму и чудному государю предстоит сыграть благороднейшую роль на земле, и он так добродетелен и благороден, что Бог не оставит его. Он исполнит своё призвание и сокрушит гидру революции, которая в лице этого убийцы и злодея стала страшнее, чем когда-либо!".to_string(),
            "— Одни мы должны отомстить за кровь праведника... На кого, спрашиваю вас, мы можем положиться?.. Англия со своим коммерческим духом не может и не сможет понять возвышенности души императора Александра. Она отказалась очистить Мальту. Она хотела найти и всё ещё ищет тайные мотивы в наших действиях. Какой ответ получил Новосильцев? Никакого. Англичане не поняли и не могут понять самоотверженности нашего государя, который ничего не хочет для себя, а желает только блага человечества. И что они обещали? Ничего! И то малое, что обещали, не исполнят!".to_string(),
            "— Пруссия всегда заявляла, что Бонапарт непобедим и что вся Европа бессильна перед ним... И я не верю ни одному слову, что говорит Гарденберг или Гаугвиц. Это знаменитое прусское нейтралитет — просто ловушка. Я верю только в Бога и в высокое призвание нашего обожаемого государя. Он спасёт Европу! — Она вдруг остановилась, улыбаясь своей порывистости. — Я думаю, — сказал князь с улыбкой, — что если бы вместо нашего дорогого Винцингероде послали вас, вы бы штурмом взяли согласие прусского короля. Вы так красноречивы. Не дадите ли вы мне чашку чаю? — Сейчас. Кстати, — добавила она, успокаиваясь, — я жду сегодня двух очень интересных людей.".to_string(),
            "— Я жду сегодня виконта де Мортемара, который через Роганов связан с Монморанси, одной из лучших французских фамилий. Он один из настоящих эмигрантов, хороших. И ещё аббата Морио. Знаете ли вы этого глубокого мыслителя? Он был принят государем. Слышали вы? — Я буду очень рад познакомиться с ними, — сказал князь. — Но скажите, — добавил он с нарочитой небрежностью, как будто вопрос только что пришёл ему в голову, хотя вопрос, который он хотел задать, был главной целью его визита, — правда ли, что вдовствующая императрица желает назначения барона Функе первым секретарём в Вену? Барон, по всем отзывам, бедное создание.".to_string(),
            "Князь Василий хотел получить это место для своего сына, но другие через вдовствующую императрицу Марию Фёдоровну старались получить его для барона. Анна Павловна почти закрыла глаза, чтобы показать, что ни она, ни кто-либо другой не имеет права судить о том, что угодно императрице или что ей приятно. — Барон Функе рекомендован вдовствующей императрице её сестрой, — сказала она только, сухим и печальным тоном. Называя императрицу, лицо Анны Павловны вдруг приняло выражение глубокой и искренней преданности и уважения, смешанного с печалью.".to_string(),
            "— А как ваше семейство? Знаете ли вы, что с тех пор, как ваша дочь вышла в свет, все были в восторге от неё? Говорят, она удивительно хороша собой. — Князь поклонился в знак уважения и благодарности. — Я часто думаю, — продолжала она после короткого молчания, придвигаясь ближе к князю и ласково улыбаясь ему, как будто показывая, что политические и светские разговоры кончились и настало время задушевной беседы, — я часто думаю, как несправедливо иногда распределяются радости жизни. Почему судьба дала вам таких двух прекрасных детей?".to_string(),
            "— Я не говорю про вашего младшего сына Анатоля. Я не люблю его, — добавила она тоном, не допускающим возражений, и поднимая брови. — Два таких прелестных ребёнка. И право, вы меньше всех цените их, и потому не заслуживаете иметь их. И она улыбнулась своей восторженной улыбкой. — Что делать, — сказал князь. — Лаватер сказал бы, что у меня нет шишки отцовства. — Не шутите; я хочу серьёзно поговорить с вами. Знаете ли вы, что я недовольна вашим младшим сыном? Между нами — лицо её приняло печальное выражение — о нём говорили у Её Величества и вас жалели...".to_string(),
            "Князь ничего не ответил, но она значительно смотрела на него, ожидая ответа. Он нахмурился. — Что вы хотите, чтобы я сделал? — сказал он наконец. — Вы знаете, я сделал всё, что мог отец для их воспитания, и оба вышли дураками. Ипполит по крайней мере тихий дурак, а Анатоль — беспокойный. В этом только разница между ними, — сказал он, улыбаясь более естественно и оживлённо, чем обыкновенно, так что морщины вокруг его рта очень ясно открывали что-то неожиданно грубое и неприятное.".to_string(),
            "— И зачем таким людям, как вы, родятся дети? Если бы вы не были отцом, я ничего не могла бы упрекнуть вас, — сказала Анна Павловна, задумчиво поднимая глаза. — Я ваш верный раб и только вам одной могу признаться, что мои дети — крест моей жизни. Это то, что я объясняю себе. Ничего не поделаешь! — Он больше ничего не сказал, но жестом выразил свою покорность жестокой судьбе. Анна Павловна задумалась. — Вы никогда не думали о том, чтобы женить вашего расточительного сына Анатоля? — спросила она. — Говорят, что у старых дев есть мания сватовства, и хотя я не чувствую ещё в себе этой слабости, я знаю одну особу, которая очень несчастлива с отцом.".to_string(),
            "— Она ваша родственница, княжна Марья Болконская. Князь Василий не ответил, хотя, с быстротой памяти и восприимчивости, свойственной светскому человеку, движением головы показал, что он принимает это к сведению. — Знаете ли вы, — сказал он наконец, очевидно не в силах удержать печальный поток своих мыслей, — что Анатоль стоит мне сорок тысяч рублей в год? И, — продолжал он после паузы, — что будет через пять лет, если он пойдёт так дальше? Вот что должны выносить отцы... Богата ли эта ваша княжна?".to_string(),
            "— Её отец очень богат и скуп. Он живёт в деревне. Это известный князь Болконский, который должен был выйти в отставку при покойном императоре и получил прозвище «прусского короля». Он очень умен, но странен и тяжел. Бедная девушка очень несчастлива. У неё есть брат; я думаю, вы знаете его, он недавно женился на Лизе Мейнен. Он адъютант Кутузова и будет сегодня вечером. — Послушайте, дорогая Аннет, — сказал князь, вдруг взяв руку Анны Павловны и по какой-то причине опуская её вниз. — Устройство мне это дело, и я всегда буду вашим самым преданным рабом.".to_string(),
            "— Я начну моё ученичество старой девы с вашего семейства, — сказала Анна Павловна. — Attendez, — сказала она, размышляя, — я поговорю сегодня же вечером с Лизой, женой молодого Болконского, и, может быть, дело уладится. Князь Василий поблагодарил её и стал ждать дочь, чтобы ехать на вечер к английскому посланнику. Анна Павловна продолжала принимать гостей и следить за тем, чтобы разговор не умолкал и был интересен для всех присутствующих.".to_string(),
            "Так начинался первый вечер в салоне Анны Павловны Шерер, где собрались представители высшего петербургского света. Здесь решались судьбы, заключались союзы, плелись интриги. Здесь начиналась история, которая станет частью великого романа Льва Толстого «Война и мир». История о любви и войне, о поиске смысла жизни и о судьбах людей на фоне исторических потрясений начала XIX века.".to_string(),
        ];
        
        Self {
            texts: fragments,
            current_index: 0,
        }
    }

    fn get_next(&mut self) -> (String, usize, usize) {
        if self.current_index >= self.texts.len() {
            self.current_index = 0;
        }
        let text = self.texts[self.current_index].clone();
        let current = self.current_index;
        let total = self.texts.len();
        self.current_index += 1;
        (text, current + 1, total)
    }

    fn reset(&mut self) {
        self.current_index = 0;
    }

    fn add_text(&mut self, text: String) {
        self.texts.push(text);
    }
}

#[derive(Serialize)]
struct TextResponse {
    text: String,
    current: usize,
    total: usize,
}

#[derive(Deserialize)]
struct AddTextRequest {
    text: String,
}

#[derive(Serialize, Deserialize)]
struct ResultResponse {
    cpm: f64,
    accuracy: f64,
    time_seconds: f64,
    correct_chars: usize,
    total_chars: usize,
}

async fn get_text(data: web::Data<Arc<Mutex<TextStore>>>) -> impl Responder {
    let mut store = data.lock().unwrap();
    let (text, current, total) = store.get_next();
    HttpResponse::Ok().json(TextResponse { text, current, total })
}

async fn add_text(
    data: web::Data<Arc<Mutex<TextStore>>>,
    body: web::Json<AddTextRequest>,
) -> impl Responder {
    let mut store = data.lock().unwrap();
    store.add_text(body.text.clone());
    HttpResponse::Ok().json(serde_json::json!({"status": "ok", "message": "Text added"}))
}

async fn reset_text(data: web::Data<Arc<Mutex<TextStore>>>) -> impl Responder {
    let mut store = data.lock().unwrap();
    store.reset();
    HttpResponse::Ok().json(serde_json::json!({"status": "ok", "message": "Index reset"}))
}

async fn calculate_result(body: web::Json<ResultResponse>) -> impl Responder {
    HttpResponse::Ok().json(body.into_inner())
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let text_store = Arc::new(Mutex::new(TextStore::new()));

    println!("🦀 Typing Speed Test Server");
    println!("📍 http://localhost:8080");
    println!("📚 Загружено фрагментов: {}", text_store.lock().unwrap().texts.len());

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(text_store.clone()))
            .route("/api/text", web::get().to(get_text))
            .route("/api/text", web::post().to(add_text))
            .route("/api/text/reset", web::post().to(reset_text))
            .route("/api/result", web::post().to(calculate_result))
            .service(Files::new("/", "./static").index_file("index.html"))
    })
    .bind("0.0.0.0:8080")?
    .run()
    .await
}
